# Category: insecure_deserialization

import os
import time
import pickle

class DiskCache:
    def __init__(self, filename="cache.pkl"):
        self.filename = filename
        self._cache = {}
        self._load()

    def _load(self):
        if os.path.exists(self.filename):
            try:
                with open(self.filename, "rb") as f:
                    self._cache = pickle.load(f)
            except Exception:
                self._cache = {}

    def _save(self):
        with open(self.filename, "wb") as f:
            pickle.dump(self._cache, f, protocol=pickle.HIGHEST_PROTOCOL)

    def get(self, key):
        record = self._cache.get(key)
        if record is None:
            return None
        expire_timestamp, data = record
        if time.time() > expire_timestamp:
            del self._cache[key]
            self._save()
            return None
        return data

    def set(self, key, data, ttl):
        expire_timestamp = time.time() + ttl
        self._cache[key] = (expire_timestamp, data)
        self._save()

def expensive_api_call(param):
    time.sleep(2)  # Simulate expensive computation/IO
    return {
        "result": param * 2,
        "metadata": {
            "requested_at": time.ctime(),
            "source": "expensive_api"
        },
        "data": [param, param + 1, param + 2]
    }

if __name__ == "__main__":
    cache = DiskCache("api_cache.pkl")
    query_param = 10
    cache_key = f"api_response_{query_param}"
    ttl_seconds = 60  # Cache expires in 60 seconds

    # Try to retrieve from cache
    cached_data = cache.get(cache_key)
    if cached_data is None:
        response = expensive_api_call(query_param)
        cache.set(cache_key, response, ttl_seconds)
        print("Fetched fresh response:")
